#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) {
    return (*(int *)a) - (*(int *)b);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *arr = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        qsort(arr, N, sizeof(int), cmp);
        int groups = 0, cur = 0;
        for (int i = 0; i < N; ++i) {
            cur++;
            if (cur > arr[i]) {
                groups++;
                cur = 1; // start new array with current element
            }
        }
        if (cur > 0) groups++;
        printf("%d\n", groups);
        free(arr);
    }
    return 0;
}

